import subprocess, json

def mcp_call(tool_name, arguments):
    proc = subprocess.Popen(
        ['python', r'C:\Users\Administrator\mcp-servers\pcan\server.py'],
        stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.PIPE
    )
    msgs = [
        {'jsonrpc':'2.0','id':0,'method':'initialize','params':{'protocolVersion':'2024-11-05','capabilities':{},'clientInfo':{'name':'test','version':'1.0'}}},
        {'jsonrpc':'2.0','method':'notifications/initialized','params':{}},
        {'jsonrpc':'2.0','id':1,'method':'tools/call','params':{'name':tool_name,'arguments':arguments}}
    ]
    stdin_data = b''.join((json.dumps(m)+'\n').encode('utf-8') for m in msgs)
    out, err = proc.communicate(input=stdin_data, timeout=10)
    lines = out.decode('utf-8', errors='replace').strip().split('\n')
    for line in lines:
        try:
            obj = json.loads(line)
            if obj.get('id') == 1:
                return obj
        except:
            pass
    return {'raw': out.decode('utf-8', errors='replace')}

